# StratifiedKFold: like KFold but preserves the class ratio in every fold.
# Critical for imbalanced targets -- without it, some folds could have
# very few positives, producing a misleadingly high or low score.
cv_scores_clf = cross_val_score(
    LogisticRegression(class_weight="balanced", max_iter=500, random_state=42),
    Xc_train_s,
    yc_train,
    cv=StratifiedKFold(n_splits=5, shuffle=True, random_state=42),
    scoring="f1",
    n_jobs=-1,
)

logger.info("LogisticRegression 5-fold CV (F1 on cancelled class):")
logger.info(f"  Per fold: {cv_scores_clf.round(4)}")
logger.info(f"  Mean:     {cv_scores_clf.mean():.4f}")
logger.info(f"  Std:      {cv_scores_clf.std():.4f}")
