## Capstone: End-to-End Training Function

Bring together every step from this notebook into a single, type-annotated, logged function. It takes a DataFrame, a list of features, a target column, and the task type, then runs the full pipeline: split, scale, fit, evaluate, save.

After implementing, run it for both targets and compare the results to the dummy baselines from Section 5.

::: {#7aa29ee5 .cell execution_count=28}
``` {.python .cell-code}
def train_and_evaluate(
    df: pd.DataFrame,
    features: list[str],
    target: str,
    task: str,
    model_dir: Path = Path("models"),
    test_size: float = 0.20,
    random_state: int = 42,
) -> dict[str, Any]:
    """Split, scale, fit, evaluate, and save a model for one target.

    Args:
        task: "regression" or "classification"

    Returns:
        Dict of evaluation metrics plus the path to the saved bundle.
    """
    X_all = df[features].to_numpy(dtype=float)
    y_all = df[target].to_numpy()

    stratify = y_all if task == "classification" else None
    X_tr, X_te, y_tr, y_te = train_test_split(
        X_all, y_all, test_size=test_size, random_state=random_state,
        stratify=stratify,
    )

    scaler_fn = StandardScaler()
    X_tr_s = scaler_fn.fit_transform(X_tr)
    X_te_s = scaler_fn.transform(X_te)

    if task == "regression":
        model = LinearRegression()
        model.fit(X_tr_s, y_tr)
        y_pred = model.predict(X_te_s)
        metrics: dict[str, float] = {
            "mae":  round(mean_absolute_error(y_te, y_pred), 4),
            "rmse": round(root_mean_squared_error(y_te, y_pred), 4),
            "r2":   round(r2_score(y_te, y_pred), 4),
        }
    else:
        from sklearn.metrics import f1_score, accuracy_score
        model = LogisticRegression(
            class_weight="balanced", max_iter=500, random_state=random_state
        )
        model.fit(X_tr_s, y_tr)
        y_pred = model.predict(X_te_s)
        metrics = {
            "accuracy": round(accuracy_score(y_te, y_pred), 4),
            "f1":       round(f1_score(y_te, y_pred), 4),
        }

    model_dir.mkdir(exist_ok=True)
    path = model_dir / f"{task}_{target}.joblib"
    joblib.dump({"scaler": scaler_fn, "model": model, "features": features}, path)

    logger.info(f"[{task}] target={target!r} | {metrics} | saved to {path}")
    return {**metrics, "path": str(path)}
```
